mapper.select:
SELECT item_id, equip_id, item_name, item_std, sort_order, apply_from_ym, del_from_ym, img_file
FROM tb_inspect_item
WHERE equip_id = #{equipId}
  AND apply_from_ym <= #{ym}
  AND (del_from_ym IS NULL OR del_from_ym > #{ym})
ORDER BY sort_order, item_id

mapper.update:
UPDATE tb_inspect_item
SET item_name=#{itemName}, item_std=#{itemStd}, sort_order=#{sortOrder}
WHERE item_id=#{itemId}

mapper.select:
SELECT header_id, equip_id, inspect_ym, inspector_name, confirmer_name, status
FROM tb_inspect_header
WHERE equip_id=#{equipId} AND inspect_ym=#{ym}

SELECT result_id, equip_id, inspect_ym, inspect_day, item_id, result
FROM tb_inspect_result
WHERE equip_id=#{equipId} AND inspect_ym=#{ym}
